// Tools.jsx
import React, { useState } from "react";
import { getGraphData, generateReport } from "./api/auth";

export default function Tools() {
  const empId = localStorage.getItem("empId");
  const [file, setFile] = useState(null);
  const [month, setMonth] = useState("");
  const [graphData, setGraphData] = useState([]);

  const uploadBill = async (e) => {
    e.preventDefault();
    if (!file) return alert("Select file");
    if (!month) return alert("Select month");

    const formData = new FormData();
    formData.append("bill", file);
    formData.append("empId", empId);
    formData.append("month_year", month);

    try {
      const res = await fetch("/api/app", {
        method: "POST",
        body: formData,
        headers: {
          action: "uploadBill",
        },
      });
      const data = await res.json();
      if (data.success) {
        alert("Bill uploaded");
      } else {
        alert("Upload failed");
      }
    } catch (err) {
      alert("Upload error");
    }
  };

  const loadGraph = async () => {
    try {
      const res = await getGraphData(empId);
      if (res.data.success) setGraphData(res.data.graph || []);
    } catch (err) {
      console.error(err);
      alert("Graph load error");
    }
  };

  const handleGenerate = async () => {
    if (!month) return alert("Select month");
    try {
      const res = await generateReport({ empId, report_month: month });
      if (res.data.success) {
        const fileUrl = res.data.file;
        window.open(fileUrl, "_blank");
      } else {
        alert("Report generation failed");
      }
    } catch {
      alert("Server error");
    }
  };

  return (
    <div style={{ padding: 20 }}>
      <h2>Tools</h2>

      <section style={{ marginTop: 12 }}>
        <h4>Upload Bill</h4>
        <form onSubmit={uploadBill}>
          <input type="file" accept="application/pdf,image/*" onChange={(e) => setFile(e.target.files[0])} />
          <input type="month" value={month} onChange={(e) => setMonth(e.target.value)} />
          <button type="submit">Upload Bill</button>
        </form>
      </section>

      <section style={{ marginTop: 20 }}>
        <h4>Monthly Graph</h4>
        <button onClick={loadGraph}>Load Graph</button>
        {/* you can render graph here using chartjs if desired */}
      </section>

      <section style={{ marginTop: 20 }}>
        <h4>Monthly Summary & Download Report</h4>
        <input type="month" value={month} onChange={(e) => setMonth(e.target.value)} />
        <button onClick={handleGenerate}>Generate & Download PDF</button>
      </section>
    </div>
  );
}
